<template>
    <div id="bgm" class="scroll_fade_up">
		<p v-html="bgm[i].bgmInfo">
		</p>
        <span @click="play++" style="text-align:center;">
            <img :src="isPlay ? './on.png' : './off.png' " :alt="isPlay ? 'Playing' : 'Paused' " width="60px" height="60px" style="padding: 0;margin: 0;">
            <audio ref="audio" :src="bgm[i].bgmSrc" @ended="audioEnd">
              Your Internet explorer's version is too low to carry on the "audio" broder.
		</audio></span><br/>
		<img :src="bgm[i].bgmImgSrc" :alt="bgm[i].bgmImgAlt" :title="bgm[i].bgmImgTitle" :class="bgm[i].bgmImgClassName"/><br>
		<div class="button_bgm">
            <button @click="bgm_pre">上一首</button>
            <button @click="bgm_nex">下一首</button>
        </div>
	</div>
</template>
<script>
export default{
    name:'Bgm_b',
    data(){
        return {
            isPlay:false,
            bgm:[
                {
                    id:'01',
                    bgmSrc:'./bgm1.flac',
                    bgmImgSrc:'./bgmimg1.png',
                    bgmImgAlt:'上海アリス幻乐団',
                    bgmImgTitle:'上海アリス幻乐団',
                    bgmInfo:'Bgm:神々が恋した幻想郷<br/>By--上海アリス幻乐団',
                    bgmImgClassName:'img1'
                },
                {
                    id:'02',
                    bgmSrc:'./bgm2.flac',
                    bgmImgSrc:'./bgmimg2.png',
                    bgmImgAlt:'HOYO-MIX',
                    bgmImgTitle:'HOYO-MIX',
                    bgmInfo:'Bgm:Surasthana Fantasia 净善的遐歌<br/>By--HOYO-MIX',
                    bgmImgClassName:'img2'
                }
            ],
            i:0,
            play:1
        }
    },
    methods: {
        bgm_nex(){
            this.i = this.i + 1;
            if(this.i >= 2){
                this.i = 0
            }
        },
        bgm_pre(){
            this.i = this.i - 1;
            if(this.i == -1){
                this.i = 1
            }
        },
        audioEnd(){
            this.isPlay = false
        }
    },
    watch:{
        play:{
            immediate: true,
            handler(nVal){
                if(nVal % 2 == 0 ){
                    this.isPlay = true;
                    this.$refs.audio.play();
                }
                else{
                    this.isPlay = false;
                    this.$refs.audio.pause();
                }
            }
        }
    }
}
</script>
<style>
    #bgm .img1{
        width:250px;
        height:50px;
        border-radius: 5%;
        border-color: #f19bd0;
    }
    #bgm .img2{
        width:250px;
        height:200px;
        border-radius: 5%;
        border-color: #f19bd0;
    }
    #bgm{
        position:fixed;
        top:5px;
        left:2px;
        text-shadow:1px 1px #8d4bbb;
        font-size:18px;
        font-family:yuanshen;
        background-color:aquamarine;
        width:17%;
        color:#ff2eff;
        transition: 1s;
        border-radius: 5%;
        height: auto;
    }
    .button_bgm{
        text-align: center;
    }
</style>